package migration

import (
	"bytes"
	"compress/gzip"
	"context"
	"crypto/sha256"
	"database/sql"
	"encoding/base64"
	"encoding/hex"
	"fmt"
	"io"
)

const (
	version2ContractDigest     = "eaf67a323a84b198864ffd9e9ef44566b1e2d9758df5235bb969e6ce7406a739"
	version2ContractGZIPBase64 = ""
)

var frozenVersion2Contract = mustDecodeVersion2Contract()

func Version2SchemaContract() []byte {
	result := make([]byte, len(frozenVersion2Contract))
	copy(result, frozenVersion2Contract)
	return result
}

func ValidateVersion2SchemaContract(ctx context.Context, connection *sql.Conn) error {
	actual, err := BuildSchemaContract(ctx, connection, 2)
	if err != nil {
		return err
	}
	if !bytes.Equal(actual, frozenVersion2Contract) {
		digest := sha256.Sum256(actual)
		return fmt.Errorf("validate version 2 schema contract: digest %x, want %s", digest, version2ContractDigest)
	}
	return nil
}

func mustDecodeVersion2Contract() []byte {
	compressed, err := base64.StdEncoding.DecodeString(version2ContractGZIPBase64)
	if err != nil {
		panic(fmt.Sprintf("decode frozen version 2 contract: %v", err))
	}
	reader, err := gzip.NewReader(bytes.NewReader(compressed))
	if err != nil {
		panic(fmt.Sprintf("open frozen version 2 contract: %v", err))
	}
	contract, err := io.ReadAll(io.LimitReader(reader, 1024*1024))
	if err != nil {
		panic(fmt.Sprintf("read frozen version 2 contract: %v", err))
	}
	if err := reader.Close(); err != nil {
		panic(fmt.Sprintf("close frozen version 2 contract: %v", err))
	}
	digest := sha256.Sum256(contract)
	if hex.EncodeToString(digest[:]) != version2ContractDigest {
		panic(fmt.Sprintf("frozen version 2 contract digest = %x, want %s", digest, version2ContractDigest))
	}
	return contract
}
